// IIIF + OpenSeadragon viewer wrapper for the Wellcome-Schreiber manuscripts.
//
// Contract:
//   window.renderSpread(containerId, leftPath, rightPath)
//     - leftPath / rightPath are the legacy path strings produced by
//       bildAnzeigeDS(), e.g. "50/Basel_KII11_001r.jpg". The wrapper
//       strips the "<digits>/" prefix and the ".jpg" suffix to derive
//       a lookup key (e.g. "Basel_KII11_001r").
//     - GUIDs are looked up in window.blattInfoIIIF_B (the mapping
//       generated by tooling/generate-iiif-mapping.js).
//     - Builds https://iiif.ub.unibe.ch/image/v3.0/{guid}/info.json
//       tile sources and renders both folios side-by-side in a single
//       OSD instance mounted in the container element.
//     - If a side has no resolvable GUID, that side is shown blank with
//       an inline error overlay; the other side still renders.
//     - Idempotent: repeated calls tear down the previous viewer and
//       mount a fresh one.
//
// Depends on: OpenSeadragon (loaded from CDN via <script> tag in the
// consuming HTML page) and window.blattInfoIIIF_B (loaded before this
// script).

(function () {
  var IIIF_BASE = 'https://iiif.ub.unibe.ch/image/v3.0/';
  // Between-page gap in OSD viewport units. Tile source #1 sits at x=0
  // with width=1; tile source #2 sits at x = 1 + SPREAD_GAP.
  var SPREAD_GAP = 0.02;
  var activeViewer = null;

  // Suppress the browser's default focus outline on the OSD container
  // and its focusable descendants. OSD sets tabindex on its wrapper and
  // canvas so it can receive keyboard events; without this rule, clicking
  // the viewer draws the browser's blue :focus ring around the canvas.
  (function injectOsdFocusStyle() {
    if (document.getElementById('osdViewer-focus-style')) return;
    var style = document.createElement('style');
    style.id = 'osdViewer-focus-style';
    style.textContent =
      '.openseadragon-container:focus,' +
      '.openseadragon-container *:focus,' +
      '.openseadragon-canvas:focus,' +
      '.openseadragon-canvas canvas:focus{outline:none;}';
    document.head.appendChild(style);
  })();

  // Per-manuscript physical-size scale, keyed by the letter in
  // blattInfoIIIF_<X>. 1.0 = the largest codex (fills the viewer as
  // before). Values < 1 frame the spread inside a larger viewport rect
  // so the folios appear smaller, hinting at the physical size relative
  // to the largest codex. Container size, zoom-in headroom, and pan
  // range are all preserved — only the initial frame changes.
  // Placeholder eyeball values — replace with real ratios once physical
  // folio dimensions are on hand (scale = thisMsWidth / largestMsWidth).
  var MANUSCRIPT_SCALE = {
    B: 0.82, // Basel KII11
    W: 0.98, // Wellcome49
    C: 1.0, // Casanatense1404
    Z: 0.52, // Basel NI1_79
    Y: 0.8, // NewYork15
  };

  // Per-image crop overrides for scans with photographic artifacts
  // (black shooting-stand borders, colour cards, etc.) that shouldn't be
  // visible in the reading view. Keyed by IIIF GUID.
  //
  // Value is a IIIF pct: region — { x, y, w, h } as percentages of the
  // master image. Example: { x: 5, y: 3, w: 92, h: 94 } crops 5% off the
  // left, 3% off the top, keeps a 92% × 94% window in the middle.
  //
  // The master IIIF asset is untouched — the server derives the crop on
  // the fly from the same info.json we'd otherwise use. Removing an entry
  // instantly restores the uncropped view.
  //
  // Caveat: cropped folios use a simple {type:'image'} tile source (one
  // JPEG at IIIF's `max` size) instead of a tiled deep-zoom pyramid. For
  // the initial folio-sized view this is imperceptible; very deep zoom
  // into a cropped folio will show JPEG resampling instead of finer tiles.
  var GUID_CROP_PCT = {
    // Example entry — replace percentages with the real borders once
    // you've measured them from the master (1929×2560 px in this case).
    // Uncomment and tune, or delete if not needed:
    //'2a0370c3-5d97-48a1-ae64-ed5e02531a27': { x: 50, y: 50, w: 94, h: 96 },
  };

  function tileSourceForGuid(guid) {
    var crop = GUID_CROP_PCT[guid];
    if (!crop) return infoJsonUrl(guid); // uncropped, deep-zoomable
    var region = 'pct:' + crop.x + ',' + crop.y + ',' + crop.w + ',' + crop.h;
    return {
      type: 'image',
      url: IIIF_BASE + guid + '/' + region + '/max/0/default.jpg',
    };
  }

  // Values the legacy code uses to mean "no image on this side". These
  // must not trigger a lookup or an error overlay — they are the
  // designed-blank sentinels for Einband/first-recto/last-verso etc.
  var BLANK_SENTINELS = /(?:^|\/)(?:transparent\.png|blind\.gif|#)$/i;

  function pathToKey(pathValue) {
    if (!pathValue) return null;
    if (BLANK_SENTINELS.test(pathValue)) return null;
    return pathValue.replace(/^\d+\//, '').replace(/\.(jpg|jpeg|png)$/i, '');
  }

  function isBlankPath(pathValue) {
    return !pathValue || BLANK_SENTINELS.test(pathValue);
  }

  // Collect every window.blattInfoIIIF_* mapping in script-tag insertion
  // order. Consumers place the manuscript-native mapping's <script> tag
  // before any fallback tags (e.g. NewYork15's page loads
  // blattInfoIIIF_Y.js first, then blattInfoIIIF_W.js for the Wellcome49
  // stems that the legacy code reuses at the Einband edges).
  //
  // Cached after the first call — mappings are static script-tag globals.
  var _mappingCache = null;
  function collectMappings() {
    if (_mappingCache) return _mappingCache;
    var mappings = [];
    var keys = Object.keys(window);
    for (var i = 0; i < keys.length; i++) {
      var name = keys[i];
      if (/^blattInfoIIIF_[A-Z]$/.test(name) && window[name] && typeof window[name] === 'object') {
        mappings.push({ name: name, map: window[name] });
      }
    }
    _mappingCache = mappings;
    return mappings;
  }

  function lookupGuid(key) {
    if (!key) return null;
    var mappings = collectMappings();
    if (mappings.length === 0) {
      console.warn('[osdViewer] no window.blattInfoIIIF_* mapping loaded');
      return null;
    }
    for (var i = 0; i < mappings.length; i++) {
      var hit = mappings[i].map[key];
      if (hit) return hit;
    }
    return null;
  }

  function infoJsonUrl(guid) {
    return IIIF_BASE + guid + '/info.json';
  }

  // The first mapping registered is the manuscript's own (any others are
  // Einband fallbacks). Its letter identifies the manuscript.
  function currentManuscriptScale() {
    var mappings = collectMappings();
    if (mappings.length === 0) return 1.0;
    var letter = mappings[0].name.slice(-1);
    var s = MANUSCRIPT_SCALE[letter];
    return typeof s === 'number' && s > 0 ? s : 1.0;
  }

  function showSideError(containerEl, side, message) {
    var overlay = document.createElement('div');
    overlay.className = 'osdSpread-error osdSpread-error-' + side;
    overlay.textContent = message;
    overlay.style.position = 'absolute';
    overlay.style.top = '50%';
    overlay.style.transform = 'translateY(-50%)';
    overlay.style.padding = '8px 12px';
    overlay.style.background = 'rgba(255, 240, 240, 0.95)';
    overlay.style.color = '#8B1B31';
    overlay.style.font = '12px Arial, Helvetica, sans-serif';
    overlay.style.border = '1px solid #8B1B31';
    overlay.style.pointerEvents = 'none';
    overlay.style.zIndex = '10';
    if (side === 'left') {
      overlay.style.left = '10%';
    } else {
      overlay.style.right = '10%';
    }
    containerEl.appendChild(overlay);
  }

  window.renderSpread = function (containerId, leftPath, rightPath) {
    var containerEl = document.getElementById(containerId);
    if (!containerEl) {
      console.warn('[osdViewer] container not found: ' + containerId);
      return;
    }

    if (typeof OpenSeadragon === 'undefined') {
      console.warn('[osdViewer] OpenSeadragon not loaded');
      containerEl.textContent = 'OpenSeadragon not loaded';
      return;
    }

    // Clean up any prior viewer/overlay state.
    if (activeViewer) {
      try { activeViewer.destroy(); } catch (_) {}
      activeViewer = null;
    }
    containerEl.innerHTML = '';

    var leftBlank = isBlankPath(leftPath);
    var rightBlank = isBlankPath(rightPath);
    var leftKey = leftBlank ? null : pathToKey(leftPath);
    var rightKey = rightBlank ? null : pathToKey(rightPath);
    var leftGuid = leftKey ? lookupGuid(leftKey) : null;
    var rightGuid = rightKey ? lookupGuid(rightKey) : null;

    if (leftKey && !leftGuid) {
      console.warn('[osdViewer] no mapping for left stem: ' + leftKey);
    }
    if (rightKey && !rightGuid) {
      console.warn('[osdViewer] no mapping for right stem: ' + rightKey);
    }

    if (!leftGuid && !rightGuid) {
      containerEl.textContent = 'No image available for this spread.';
      return;
    }

    // Layout is height-normalized: both folios sit on the same top and
    // bottom edge (viewport height = 1), and their widths follow each
    // image's actual aspect ratio. This mirrors how a bifolium physically
    // looks — folios of the same height, possibly differing widths — and
    // prevents the shorter-image "gap at the bottom" that a width-based
    // layout produces when the two scans have different aspect ratios.
    //
    // Requires each side's info.json ahead of OSD init so we know the
    // aspect ratios. On fetch failure we fall back to width=1 for that
    // side (its own aspect ratio will be discovered by OSD from the same
    // info.json anyway, at the cost of possibly re-introducing a gap).
    Promise.all([
      leftGuid  ? fetchAspectRatio(leftGuid)  : Promise.resolve(null),
      rightGuid ? fetchAspectRatio(rightGuid) : Promise.resolve(null),
    ]).then(function (aspects) {
      // aspects[1] (right AR) isn't needed here: OSD derives each source's
      // displayed width from its own info.json when we pin height=1. We
      // only need the left AR to know where the right source starts on x.
      var leftAR = aspects[0]; // width / height, or null

      var tileSources = [];
      var leftWidthVU = leftAR || 1; // fallback: unit width if AR unknown
      if (leftGuid) {
        tileSources.push({
          tileSource: tileSourceForGuid(leftGuid),
          x: 0,
          y: 0,
          height: 1,
        });
      }
      if (rightGuid) {
        tileSources.push({
          tileSource: tileSourceForGuid(rightGuid),
          x: leftWidthVU + SPREAD_GAP,
          y: 0,
          height: 1,
        });
      }

      startViewer(tileSources);
    });

    function startViewer(tileSources) {
    activeViewer = OpenSeadragon({
      element: containerEl,
      prefixUrl: 'https://cdn.jsdelivr.net/npm/openseadragon@4/build/openseadragon/images/',
      tileSources: tileSources,
      showNavigator: false,
      showRotationControl: false,
      collectionMode: false,
      crossOriginPolicy: 'Anonymous',
      ajaxWithCredentials: false,
      // Pan/zoom feel: smooth but not laggy.
      //   animationTime — how long OSD takes to catch up with input.
      //     0 = instant snap, 1.2 = OSD default (glidy). 0.4 = smooth
      //     drag response, not sluggish.
      //   springStiffness — how tightly the view clamps to the target.
      //     Higher = less bouncy/wobbly. Default 6.5, we want firmer.
      //   zoomPerScroll — wheel-zoom step size. Default 1.2 (chunky).
      //     1.15 = brisk but smooth; large IIIF rasters need to
      //     traverse a lot of scale in few wheel notches.
      animationTime: 0.4,
      springStiffness: 15,
      zoomPerScroll: 1.6,
      // Don't zoom on a plain click — the folios are static pages,
      // not a map. Double-click still zooms as a discoverable gesture.
      gestureSettingsMouse: { clickToZoom: false, dblClickToZoom: true },
      gestureSettingsTouch: { clickToZoom: false, dblClickToZoom: true },
      gestureSettingsPen:   { clickToZoom: false, dblClickToZoom: true },
    });

    // Frame the spread inside a larger viewport rect when this manuscript
    // is physically smaller than the reference codex. Runs after 'open'
    // so viewport.getHomeBounds() reflects the actual tile-source layout.
    var scale = currentManuscriptScale();
    if (scale < 1.0) {
      activeViewer.addHandler('open', function () {
        var vp = activeViewer.viewport;
        var natural = vp.getHomeBounds();
        var inv = 1 / scale;
        var w = natural.width * inv;
        var h = natural.height * inv;
        var x = natural.x - (w - natural.width) / 2;
        var y = natural.y - (h - natural.height) / 2;
        var framed = new OpenSeadragon.Rect(x, y, w, h);

        // Override so the home button / goHome() returns to the framed
        // view instead of OSD's tight fit around the tile sources.
        vp.getHomeBounds = function () { return framed; };

        vp.fitBounds(framed, true);
      });
    }

    // Attach failure handlers per-item after they open.
    activeViewer.addHandler('open-failed', function (evt) {
      console.warn('[osdViewer] open-failed', evt);
      containerEl.appendChild(makeInlineBanner('IIIF image failed to load. Check network / CORS / info.json.'));
    });
    activeViewer.addHandler('tile-load-failed', function (evt) {
      // Tile-level failures are noisy; log once per source instead of once per tile.
      if (!containerEl.querySelector('.osdSpread-error-tile')) {
        var el = makeInlineBanner('Some tiles failed to load — image may be incomplete.');
        el.classList.add('osdSpread-error-tile');
        containerEl.appendChild(el);
      }
      console.warn('[osdViewer] tile-load-failed', evt);
    });

    } // end startViewer

    // If a side's GUID was missing, mark it in the overlay layer. Blank
    // sentinels (transparent.png / blind.gif) are intentional — skip the
    // overlay so those sides read as designed-blank, not as errors.
    // Runs synchronously — the fetch above only affects tile-source
    // placement, not whether we can flag a missing GUID.
    if (!leftGuid && !leftBlank) {
      showSideError(containerEl, 'left', leftKey ? ('No IIIF mapping for ' + leftKey) : 'No image');
    }
    if (!rightGuid && !rightBlank) {
      showSideError(containerEl, 'right', rightKey ? ('No IIIF mapping for ' + rightKey) : 'No image');
    }
  };

  // Fetch a IIIF info.json and return the *displayed* aspect ratio
  // (width / height) for this GUID. If the GUID has a crop override in
  // GUID_CROP_PCT, the aspect ratio reflects the cropped region — so the
  // right folio's x-position stays flush with the visible edge of the
  // left folio, not the original master's edge.
  //
  // Resolves to null on any failure so callers can fall back gracefully.
  // Cached per GUID (renderSpread runs on every page turn; aspect ratios
  // never change for a given image + crop combination).
  var _aspectCache = {};
  function fetchAspectRatio(guid) {
    if (_aspectCache[guid] !== undefined) return Promise.resolve(_aspectCache[guid]);
    return fetch(infoJsonUrl(guid))
      .then(function (r) { return r.ok ? r.json() : null; })
      .then(function (info) {
        if (!info || !info.width || !info.height) {
          _aspectCache[guid] = null;
          return null;
        }
        var w = info.width;
        var h = info.height;
        var crop = GUID_CROP_PCT[guid];
        if (crop) {
          w = info.width  * (crop.w / 100);
          h = info.height * (crop.h / 100);
        }
        var ar = w / h;
        _aspectCache[guid] = ar;
        return ar;
      })
      .catch(function () {
        _aspectCache[guid] = null;
        return null;
      });
  }

  function makeInlineBanner(message) {
    var el = document.createElement('div');
    el.className = 'osdSpread-error';
    el.textContent = message;
    el.style.position = 'absolute';
    el.style.top = '8px';
    el.style.left = '50%';
    el.style.transform = 'translateX(-50%)';
    el.style.padding = '6px 10px';
    el.style.background = 'rgba(255, 240, 240, 0.95)';
    el.style.color = '#8B1B31';
    el.style.font = '12px Arial, Helvetica, sans-serif';
    el.style.border = '1px solid #8B1B31';
    el.style.zIndex = '10';
    el.style.pointerEvents = 'none';
    return el;
  }

  // Arrow-key page turning. Captured on the document before OSD's own
  // key tracker can pan the canvas, so ← / → always turn pages instead.
  // Skips when focus is in a form control (Blatt input, section select)
  // or when modifier keys are held.
  function isEditableTarget(t) {
    if (!t) return false;
    var tag = t.tagName;
    if (tag === 'INPUT' || tag === 'TEXTAREA' || tag === 'SELECT') return true;
    return t.isContentEditable === true;
  }

  document.addEventListener('keydown', function (e) {
    if (e.key !== 'ArrowLeft' && e.key !== 'ArrowRight') return;
    if (e.ctrlKey || e.metaKey || e.altKey) return;
    if (isEditableTarget(e.target)) return;

    var handler = e.key === 'ArrowRight' ? window.goNextPage : window.goPrevPage;
    if (typeof handler !== 'function') return;

    e.preventDefault();
    e.stopPropagation();
    handler();
  }, true);
})();
